import subprocess

def get_ls_result(dir_path: str) -> str:
    try:
        result = subprocess.run(
            ['ls', '-l'],
            capture_output=True,
            text=True,
            check=False,
            cwd=dir_path
        )
        if result.returncode != 0:
            return ""
        return result.stdout
    except:
        return ""

def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    if info_type not in {'lang', 'encoding', 'cache'}:
        return header
    header_key = {
        'lang': 'Accept-Language',
        'encoding': 'Accept-Encoding',
        'cache': 'Cache-Control'
    }[info_type]
    new_header = header.copy()
    new_header[header_key] = info_content
    return new_header

