import re

def checkAdminPassword(password):
    if not password:
        return False
    if len(password) < 12:
        return False
    if not re.search(r'[A-Z]', password):
        return False
    if not re.search(r'[a-z]', password):
        return False
    if not re.search(r'[0-9]', password):
        return False
    if not re.search(r'[!@#$%^&*()_+-=[]{}|;\'":,.<>/?]', password):
        return False
    common_weak = {'password', '123456', 'admin', 'qwerty', 'letmein', '123456789', '1234567890'}
    if password.lower() in common_weak:
        return False
    return True

